#include <iostream>

int main() {
    int n;
    std::cin >> n;
    if (n <= 2) {
        std::cout << 1 << std::endl;
        return 0;
    }
    int a = 1, b = 1, c;
    for (int i = 3; i <= n; i++) {
        c = a + b;
        a = b;
        b = c;
    }
    std::cout << b << std::endl;
    return 0;
}
